import json
import os
from urllib.parse import urlparse, unquote

import psycopg2
from psycopg2.extras import RealDictCursor

DATABASE_URL = os.environ.get(
    "DATABASE_URL",
    "postgresql://admin:password@internal-db.us-east-1.rds.amazonaws.com:5432/production",
)


def parse_database_url(db_url):
    parsed = urlparse(db_url)
    return {
        "host": parsed.hostname,
        "port": parsed.port or 5432,
        "dbname": parsed.path.lstrip("/"),
        "user": parsed.username,
        "password": parsed.password,
        "sslmode": "require",
    }


def run_query(query, params=None):
    conn = psycopg2.connect(**parse_database_url(DATABASE_URL))
    try:
        with conn.cursor(cursor_factory=RealDictCursor) as cur:
            cur.execute(query, params or ())
            if cur.description:
                rows = cur.fetchall()
                return rows
            conn.commit()
            return []
    finally:
        conn.close()


def lambda_handler(event, context):
    try:
        query = event.get("query") or "SELECT NOW() AS current_time"
        params = event.get("params") or None

        rows = run_query(query, params)

        return {
            "statusCode": 200,
            "headers": {
                "Content-Type": "application/json"
            },
            "body": json.dumps({
                "success": True,
                "count": len(rows),
                "results": rows,
            }, default=str),
        }
    except Exception as e:
        return {
            "statusCode": 500,
            "headers": {
                "Content-Type": "application/json"
            },
            "body": json.dumps({
                "success": False,
                "error": str(e),
            }),
        }